// before / after toggle
document.querySelectorAll('.ba-toggle button').forEach(function (btn) {
	btn.addEventListener('click', function () {
		var t = btn.dataset.t,
			v = btn.dataset.v
		document.querySelectorAll('.ba-toggle button[data-t="' + t + '"]').forEach(function (b) {
			b.classList.remove('active')
			b.setAttribute('aria-pressed', 'false')
		})
		btn.classList.add('active')
		btn.setAttribute('aria-pressed', 'true')
		var img = document.querySelector('.ba-img[data-t="' + t + '"]')
		var nsrc = v === 'b' ? BA[t].b : BA[t].a
		if (img.getAttribute('src') !== nsrc) {
			img.style.opacity = 0
			setTimeout(function () {
				img.src = nsrc
				img.style.opacity = 1
			}, 160)
		}
		img.alt = img.dataset.title + (v === 'b' ? ' before revision' : ' after revision')
	})
})
