// scroll reveal
var io = new IntersectionObserver(
	function (es) {
		es.forEach(function (e) {
			if (e.isIntersecting) {
				e.target.classList.add('in')
				io.unobserve(e.target)
			}
		})
	},
	{ threshold: 0.12 },
)
document.querySelectorAll('.reveal').forEach(function (el) {
	io.observe(el)
})

// scroll progress bar
var sb = document.getElementById('scrollbar')
function onScroll() {
	var d = document.documentElement
	var p = d.scrollTop / (d.scrollHeight - d.clientHeight || 1)
	sb.style.width = p * 100 + '%'
}
document.addEventListener('scroll', onScroll, { passive: true })
onScroll()

// count up stats
var counted = new WeakSet()
var statIO = new IntersectionObserver(
	function (es) {
		es.forEach(function (e) {
			if (e.isIntersecting && !counted.has(e.target)) {
				counted.add(e.target)
				var el = e.target,
					target = +el.dataset.count,
					t0 = null,
					dur = 900
				function step(ts) {
					if (!t0) t0 = ts
					var k = Math.min((ts - t0) / dur, 1)
					el.textContent = Math.round((1 - Math.pow(1 - k, 3)) * target)
					if (k < 1) requestAnimationFrame(step)
				}
				requestAnimationFrame(step)
			}
		})
	},
	{ threshold: 0.7 },
)
document.querySelectorAll('.stat .n[data-count]').forEach(function (el) {
	statIO.observe(el)
})

// scrollspy nav highlight
var spy = new IntersectionObserver(
	function (es) {
		es.forEach(function (e) {
			if (e.isIntersecting) {
				document.querySelectorAll('.nav-links a').forEach(function (a) {
					a.classList.toggle('active', a.getAttribute('href') === '#' + e.target.id)
				})
			}
		})
	},
	{ rootMargin: '-45% 0px -50% 0px' },
)
;['problem', 'solution', 'process', 'demo', 'reflection', 'team'].forEach(function (id) {
	var s = document.getElementById(id)
	if (s) spy.observe(s)
})

// hero card 3D tilt (pointer + motion safe)
var reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches
var art = document.querySelector('.hero-art'),
	stall = document.querySelector('.stall')
if (art && stall && !reduce && window.matchMedia('(pointer:fine)').matches) {
	art.addEventListener('mousemove', function (ev) {
		var r = art.getBoundingClientRect()
		var x = (ev.clientX - r.left) / r.width - 0.5,
			y = (ev.clientY - r.top) / r.height - 0.5
		stall.style.transform = 'rotateY(' + x * 9 + 'deg) rotateX(' + -y * 9 + 'deg)'
	})
	art.addEventListener('mouseleave', function () {
		stall.style.transform = ''
	})
}

// scan-to-verify hero
;(function () {
	var hero = document.querySelector('.hero-art')
	if (!hero) return
	var vf = document.getElementById('viewfinder')
	var reduceM = window.matchMedia('(prefers-reduced-motion: reduce)').matches
	function verify() {
		hero.classList.remove('scanning')
		hero.classList.add('verified')
	}
	function scan() {
		if (reduceM) {
			verify()
			return
		}
		hero.classList.remove('verified')
		void hero.offsetWidth
		hero.classList.add('scanning')
		clearTimeout(window.__scanT)
		window.__scanT = setTimeout(verify, 1350)
	}
	setTimeout(scan, 550)
	if (vf) vf.addEventListener('click', scan)
})()

// how-might-we typewriter
;(function () {
	var q = document.querySelector('.hmw .q')
	if (!q) return
	if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return
	function wrap(el) {
		Array.prototype.slice.call(el.childNodes).forEach(function (n) {
			if (n.nodeType === 3) {
				var frag = document.createDocumentFragment()
				n.textContent.split(/(\s+)/).forEach(function (tok) {
					if (tok === '') return
					if (/^\s+$/.test(tok)) {
						frag.appendChild(document.createTextNode(tok))
						return
					}
					var w = document.createElement('span')
					w.className = 'word'
					tok.split('').forEach(function (c) {
						var s = document.createElement('span')
						s.className = 'ch'
						s.textContent = c
						w.appendChild(s)
					})
					frag.appendChild(w)
				})
				el.replaceChild(frag, n)
			} else if (n.nodeType === 1) {
				wrap(n)
			}
		})
	}
	wrap(q)
	var chs = q.querySelectorAll('.ch')
	chs.forEach(function (s, i) {
		s.style.setProperty('--i', i)
	})
	var caret = document.createElement('span')
	caret.className = 'caret'
	caret.setAttribute('aria-hidden', 'true')
	q.appendChild(caret)
	var io = new IntersectionObserver(
		function (es) {
			es.forEach(function (e) {
				if (!e.isIntersecting) return
				io.disconnect()
				q.classList.add('typing')
				var i = 0
				var timer = setInterval(function () {
					if (i >= chs.length) {
						clearInterval(timer)
						setTimeout(function () {
							q.classList.add('done')
						}, 650)
						return
					}
					var ch = chs[i]
					ch.parentNode.insertBefore(caret, ch.nextSibling)
					i++
				}, 25)
			})
		},
		{ threshold: 0.45 },
	)
	io.observe(q)
})()

// task demo clips : load from data-src, reveal + play on success
document.querySelectorAll('.demo-vid[data-src]').forEach(function (v) {
	var scr = v.closest('.scr')
	var rate = v.dataset.rate
		? parseFloat(v.dataset.rate)
		: v.classList.contains('chat-video')
			? 1.2
			: 1
	v.loop = true
	v.muted = true
	v.defaultMuted = true
	v.autoplay = true
	v.playsInline = true
	v.preload = 'auto'
	v.defaultPlaybackRate = rate
	v.playbackRate = rate
	v.addEventListener('loadeddata', function () {
		if (scr) scr.classList.add('has-vid')
		v.currentTime = 0
		v.playbackRate = rate
		var pr = v.play()
		if (pr && pr.catch) pr.catch(function () {})
	})
	v.addEventListener('ended', function () {
		v.currentTime = 0
		v.playbackRate = rate
		var pr = v.play()
		if (pr && pr.catch) pr.catch(function () {})
	})
	v.addEventListener('error', function () {
		if (scr) scr.classList.remove('has-vid')
	})
	v.src = v.dataset.src
})
